231	    protected void writeList(PDFList list) throws IOException {
232	        for (ListItem item : list.getListItems()) {
233	            if (!isInsideTable()) {
234	                markdownWriter.write(MarkdownSyntax.LIST_ITEM);
235	                markdownWriter.write(MarkdownSyntax.SPACE);
236	            }
237	            markdownWriter.write(getCorrectMarkdownString(item.toString()));
238	            writeLineBreak();
239	
240	            List<IObject> itemContents = item.getContents();
241	            if (!itemContents.isEmpty()) {
242	                writeLineBreak();
243	                writeContents(itemContents, false);
244	            }
245	        }
246	    }
