248	    protected void writeSemanticTextNode(SemanticTextNode textNode) throws IOException {
249	        String value = textNode.getValue();
250	        if (StaticContainers.isKeepLineBreaks()) {
251	            if (textNode instanceof SemanticHeading) {
252	                value = value.replace(MarkdownSyntax.LINE_BREAK, MarkdownSyntax.SPACE);
253	            } else if (isInsideTable()) {
254	                value = value.replace(MarkdownSyntax.LINE_BREAK, getLineBreak());
255	            }
256	        } else if (isInsideTable()) {
257	            // Always replace line breaks with space in table cells for proper markdown table formatting
258	            value = value.replace(MarkdownSyntax.LINE_BREAK, MarkdownSyntax.SPACE);
259	        }
260	
261	        markdownWriter.write(getCorrectMarkdownString(value));
262	    }
