319	            int headingLevel = Math.min(6, Math.max(1, heading.getHeadingLevel()));
320	            for (int i = 0; i < headingLevel; i++) {
321	                markdownWriter.write(MarkdownSyntax.HEADING_LEVEL);
322	            }
