16	package org.opendataloader.pdf.processors;
17	
18	import org.verapdf.wcag.algorithms.entities.IObject;
19	import org.verapdf.wcag.algorithms.entities.SemanticTextNode;
20	import org.verapdf.wcag.algorithms.entities.content.LineArtChunk;
21	import org.verapdf.wcag.algorithms.entities.content.TextChunk;
22	import org.verapdf.wcag.algorithms.entities.content.TextLine;
23	import org.verapdf.wcag.algorithms.entities.geometry.BoundingBox;
24	import org.verapdf.wcag.algorithms.entities.tables.tableBorders.TableBorder;
25	import org.verapdf.wcag.algorithms.semanticalgorithms.utils.ChunksMergeUtils;
26	import org.verapdf.wcag.algorithms.semanticalgorithms.utils.ListUtils;
27	import org.verapdf.wcag.algorithms.semanticalgorithms.utils.TextChunkUtils;
28	
29	import java.util.ArrayList;
30	import java.util.Comparator;
31	import java.util.List;
32	
33	public class TextLineProcessor {
34	
35	    private static final double ONE_LINE_PROBABILITY = 0.75;
36	    private static final Comparator<TextChunk> TEXT_CHUNK_COMPARATOR =
37	        Comparator.comparingDouble(o -> o.getBoundingBox().getLeftX());
38	
39	    public static List<IObject> processTextLines(List<IObject> contents) {
40	        List<IObject> newContents = new ArrayList<>();
41	        TextLine previousLine = new TextLine(new TextChunk(""));
42	        boolean isSeparateLine = false;
43	        for (IObject content : contents) {
44	            if (content instanceof TextChunk) {
45	                TextChunk textChunk = (TextChunk) content;
46	                if (textChunk.isWhiteSpaceChunk() || textChunk.isEmpty()) {
47	                    continue;
48	                }
49	                TextLine currentLine = new TextLine(textChunk);
50	                double oneLineProbability = ChunksMergeUtils.countOneLineProbability(new SemanticTextNode(), previousLine, currentLine);
51	                isSeparateLine |= (oneLineProbability < ONE_LINE_PROBABILITY) || previousLine.isHiddenText() != currentLine.isHiddenText();
52	                if (isSeparateLine) {
53	                    previousLine.setBoundingBox(new BoundingBox(previousLine.getBoundingBox()));
54	                    previousLine = currentLine;
55	                    newContents.add(previousLine);
56	                } else {
57	                    previousLine.add(currentLine);
58	                }
59	                isSeparateLine = false;
60	            } else {
61	                if (content instanceof TableBorder) {
62	                    isSeparateLine = true;
63	                }
64	                newContents.add(content);
65	            }
66	        }
67	        for (int i = 0; i < newContents.size(); i++) {
68	            IObject content = newContents.get(i);
69	            if (content instanceof TextLine) {
70	                TextLine textLine = (TextLine) content;
71	                textLine.getTextChunks().sort(TEXT_CHUNK_COMPARATOR);
72	                double threshold = textLine.getFontSize() * TextChunkUtils.TEXT_LINE_SPACE_RATIO;
73	                newContents.set(i, getTextLineWithSpaces(textLine, threshold));
74	            }
75	        }
76	        linkTextLinesWithConnectedLineArtBullet(newContents);
77	        return newContents;
78	    }
79	
80	    private static TextLine getTextLineWithSpaces(TextLine textLine, double threshold) {
81	        List<TextChunk> textChunks = textLine.getTextChunks();
82	        TextChunk currentTextChunk = textChunks.get(0);
83	        double previousEnd = currentTextChunk.getBoundingBox().getRightX();
84	        TextLine newLine = new TextLine();
85	        newLine.add(currentTextChunk);
86	        for (int i = 1; i < textChunks.size(); i++) {
87	            currentTextChunk = textChunks.get(i);
88	            double currentStart = currentTextChunk.getBoundingBox().getLeftX();
89	            if (currentStart - previousEnd > threshold) {
90	                BoundingBox spaceBBox = new BoundingBox(currentTextChunk.getBoundingBox());
91	                spaceBBox.setLeftX(previousEnd);
92	                spaceBBox.setRightX(currentStart);
93	                TextChunk spaceChunk = new TextChunk(spaceBBox, " ", textLine.getFontSize(), textLine.getBaseLine());
94	                newLine.add(spaceChunk);
95	            }
96	            previousEnd = currentTextChunk.getBoundingBox().getRightX();
97	            newLine.add(currentTextChunk);
98	        }
99	
100	        return newLine;
101	    }
102	
103	    private static void linkTextLinesWithConnectedLineArtBullet(List<IObject> contents) {
104	        LineArtChunk lineArtChunk = null;
105	        for (IObject content : contents) {
106	            if (content instanceof LineArtChunk) {
107	                lineArtChunk = (LineArtChunk) content;
108	                continue;
109	            }
110	            if (content instanceof TableBorder) {
111	                lineArtChunk = null;
112	            }
113	            if (content instanceof TextLine && lineArtChunk != null) {
114	                TextLine textLine = (TextLine) content;
115	                if (isLineConnectedWithLineArt(textLine, lineArtChunk)) {
116	                    textLine.setConnectedLineArtLabel(lineArtChunk);
117	                }
118	                lineArtChunk = null;
119	            }
120	        }
121	    }
122	
123	    private static boolean isLineConnectedWithLineArt(TextLine textLine, LineArtChunk lineArt) {
124	        return lineArt.getRightX() <= textLine.getLeftX() && lineArt.getBoundingBox().getHeight() <
125	                ListUtils.LIST_LABEL_HEIGHT_EPSILON * textLine.getBoundingBox().getHeight();
126	    }
127	}
