36	    public static List<IObject> processParagraphs(List<IObject> contents) {
37	        DocumentProcessor.setIndexesForContentsList(contents);
38	        List<TextBlock> blocks = new ArrayList<>();
39	        for (IObject content : contents) {
40	            if (content instanceof TextLine) {
41	                blocks.add(new TextBlock((TextLine) content));
42	            }
43	        }
44	        blocks = detectParagraphsWithJustifyAlignments(blocks);
45	        blocks = detectFirstAndLastLinesOfParagraphsWithJustifyAlignments(blocks);
46	        blocks = detectParagraphsWithLeftAlignments(blocks, true);
47	        blocks = detectParagraphsWithLeftAlignments(blocks, false);
48	        blocks = detectFirstLinesOfParagraphWithLeftAlignments(blocks);
49	        blocks = detectTwoLinesParagraphs(blocks);
50	        blocks = detectParagraphsWithCenterAlignments(blocks);
51	        blocks = detectParagraphsWithRightAlignments(blocks);
52	        blocks = processOtherLines(blocks);
53	        return getContentsWithDetectedParagraphs(contents, blocks);
54	    }
55	
56	    private static List<IObject> getContentsWithDetectedParagraphs(List<IObject> contents, List<TextBlock> blocks) {
57	        List<IObject> newContents = new ArrayList<>();
58	        Iterator<TextBlock> iterator = blocks.iterator();
59	        TextBlock currentBlock = iterator.hasNext() ? iterator.next() : null;
60	        Integer currentIndex = currentBlock != null ? currentBlock.getFirstLine().getIndex() : null;
61	        for (int index = 0; index < contents.size(); index++) {
62	            IObject content = contents.get(index);
63	            if (!(content instanceof TextLine)) {
64	                newContents.add(content);
65	            } else if (Objects.equals(currentIndex, index)) {
66	                newContents.add(createParagraphFromTextBlock(currentBlock));
67	                currentBlock = iterator.hasNext() ? iterator.next() : null;
68	                currentIndex = currentBlock != null ? currentBlock.getFirstLine().getIndex() : null;
