218	        if (previousBlock.getLinesNumber() != 1) {
219	            if (previousBlock.getTextAlignment() == TextAlignment.JUSTIFY) {
220	                if (!haveSameStyle) {
221	                    return false;
222	                }
223	                areShouldBeCloseLines = true;
224	            } else if (previousBlock.getTextAlignment() != TextAlignment.LEFT) {
225	                return false;
226	            }
227	        }
