474	                                             double probability) {
475	        if (nextBlock.getLinesNumber() != 1) {
476	            return false;
477	        }
478	        if (textAlignment != TextAlignment.LEFT) {
479	            return false;
480	        }
481	        if (!areTextBlocksHaveSameTextSize(previousBlock, nextBlock)) {
482	            return false;
483	        }
484	        if (previousBlock.getTextAlignment() != TextAlignment.JUSTIFY) {
485	            return false;
486	        }
487	        if (previousBlock.isHasEndLine()) {
488	            return false;
489	        }
