496	    public static SemanticParagraph createParagraphFromTextBlock(TextBlock textBlock) {
497	        SemanticParagraph textParagraph = new SemanticParagraph();
498	        textParagraph.getColumns().add(new TextColumn());
499	        textParagraph.getLastColumn().getBlocks().add(textBlock);
500	        textParagraph.setBoundingBox(textBlock.getBoundingBox());
501	        textParagraph.setCorrectSemanticScore(1.0);
502	        textParagraph.setHiddenText(textBlock.isHiddenText());
503	        return textParagraph;
504	    }
505	
506	    private static double getDifferentLinesProbability(TextBlock previousBlock, TextBlock nextBlock,
507	                                                       boolean areSupportNotSingleLines, boolean areShouldBeCloseLines) {
508	        if (previousBlock.isHiddenText() != nextBlock.isHiddenText()) {
509	            return 0;
510	        }
511	        if (previousBlock.getLinesNumber() == 1 && nextBlock.getLinesNumber() == 1) {
512	            return ChunksMergeUtils.mergeLeadingProbability(previousBlock.getLastLine(), nextBlock.getFirstLine());
513	        }
514	        if (previousBlock.getLinesNumber() == 1) {
515	            return ChunksMergeUtils.mergeLeadingProbability(previousBlock.getLastLine(), nextBlock, areShouldBeCloseLines);
516	        }
517	        if (nextBlock.getLinesNumber() == 1) {
518	            return ChunksMergeUtils.mergeLeadingProbability(previousBlock, nextBlock.getFirstLine(), areShouldBeCloseLines);
519	        }
520	        if (areSupportNotSingleLines) {
521	            return ChunksMergeUtils.mergeLeadingProbability(previousBlock, nextBlock);
522	        }
523	        return 0;
524	    }
