526	    private static boolean areCloseStyle(TextBlock previousBlock, TextBlock nextBlock) {
527	        return NodeUtils.areCloseNumbers(previousBlock.getFontSize(), nextBlock.getFontSize(), 1e-1) &&
528	            NodeUtils.areCloseNumbers(previousBlock.getFirstLine().getFirstTextChunk().getFontWeight(),
529	                nextBlock.getFirstLine().getFirstTextChunk().getFontWeight(), 1e-1);
530	    }
531	
532	    private static boolean areTextBlocksHaveSameTextSize(TextBlock firstBlock, TextBlock secondBlock) {
533	        for (Double textSize1 : firstBlock.getTextSizes()) {
534	            for (Double textSize2 : secondBlock.getTextSizes()) {
535	                if (NodeUtils.areCloseNumbers(textSize1, textSize2)) {
536	                    return true;
537	                }
538	            }
539	        }
540	        return false;
541	    }
