public static void mergeCloseTextChunks(List<IObject> contents) {
        for (int i = 0; i < contents.size() - 1; i++) {
            IObject object = contents.get(i);
            IObject nextObject = contents.get(i + 1);
            if (object instanceof TextChunk && nextObject instanceof TextChunk) {
                TextChunk textChunk = (TextChunk) object;
                TextChunk nextTextChunk = (TextChunk) nextObject;
                if (TextChunkUtils.areTextChunksHaveSameStyle(textChunk, nextTextChunk) &&
                    TextChunkUtils.areTextChunksHaveSameBaseLine(textChunk, nextTextChunk) &&
                    areNeighborsTextChunks(textChunk, nextTextChunk)) {
                    contents.set(i, null);
                    TextChunk merged = TextChunkUtils.unionTextChunks(textChunk, nextTextChunk);
                    // unionTextChunks concatenates values without a space, but separate words
                    // need a space between them. Add one when there is a gap between chunks.
                    double gap = nextTextChunk.getTextStart() - textChunk.getTextEnd();
                    if (gap > 0) {
                        String val1 = textChunk.getValue();
                        String val2 = nextTextChunk.getValue();
                        if (!val1.isEmpty() && !val2.isEmpty()
                            && !Character.isWhitespace(val1.charAt(val1.length() - 1))
                            && !Character.isWhitespace(val2.charAt(0))) {
                            merged.setValue(val1 + " " + val2);
                        }
                    }
                    contents.set(i + 1, merged);
                }
            }
        }
    }

