                    contents.set(i, null);
                    double gap = nextTextChunk.getTextStart() - textChunk.getTextEnd();
                    boolean needsSpace = gap > 0;
                    String val1 = textChunk.getValue();
                    String val2 = nextTextChunk.getValue();
                    if (needsSpace && !val1.isEmpty() && !val2.isEmpty()
                        && !Character.isWhitespace(val1.charAt(val1.length() - 1))
                        && !Character.isWhitespace(val2.charAt(0))) {
                        // unionTextChunks concatenates values without a space, so we need to
                        // temporarily update the value of the first chunk to include a trailing
                        // space, then let unionTextChunks handle the concatenation.
                        // We also need to update symbolEnds to maintain consistency with the new value.
                        String origVal1 = textChunk.getValue();
                        List<Double> origSymbolEnds = textChunk.getSymbolEnds();
                        // Calculate the width of the space (approximate based on gap)
                        double spaceWidth = gap;
