                        double lastEnd = origSymbolEnds.get(origSymbolEnds.size() - 1);
                        newSymbolEnds.add(lastEnd + spaceWidth);
                        textChunk.setValue(val1 + " ");
                        textChunk.setSymbolEnds(newSymbolEnds);
