                    areNeighborsTextChunks(textChunk, nextTextChunk)) {
                    contents.set(i, null);
                    double gap = nextTextChunk.getTextStart() - textChunk.getTextEnd();
                    boolean needsSpace = gap > 0;
                    String val1 = textChunk.getValue();
                    String val2 = nextTextChunk.getValue();
                    if (needsSpace && !val1.isEmpty() && !val2.isEmpty()
                        && !Character.isWhitespace(val1.charAt(val1.length() - 1))
                        && !Character.isWhitespace(val2.charAt(0))) {
                        // unionTextChunks concatenates values without a space, but separate
