                        // Temporarily modify the first chunk's value and symbolEnds to
                        // include the space, so unionTextChunks produces the correct result.
                        String origVal1 = textChunk.getValue();
                        List<Double> origSymbolEnds = textChunk.getSymbolEnds();
                        List<Double> newSymbolEnds = new ArrayList<>(origSymbolEnds);
                        double lastEnd = origSymbolEnds.get(origSymbolEnds.size() - 1);
                        newSymbolEnds.add(lastEnd + gap);
                        textChunk.setValue(val1 + " ");
                        textChunk.setSymbolEnds(newSymbolEnds);
                        TextChunk merged = TextChunkUtils.unionTextChunks(textChunk, nextTextChunk);
                        // Restore original state of textChunk
                        textChunk.setValue(origVal1);
                        textChunk.setSymbolEnds(origSymbolEnds);
                        contents.set(i + 1, merged);
                    } else {
                        contents.set(i + 1, TextChunkUtils.unionTextChunks(textChunk, nextTextChunk));
                    }
                }
            }
        }
    }

