/**
 * Regression test for issue with words concatenation: text chunks with a small but
 * meaningful gap should be merged with a space between them.
 */
@Test
public void testMergeCloseTextChunksWithGapInsertsSpace() {
    List<IObject> contents = new ArrayList<>();
    String fontName = "Arial";

    // Chunk "Evolution" ending at x=70
    TextChunk chunk1 = new TextChunk(new BoundingBox(0, 10.0, 100.0, 70.0, 110.0),
        "Evolution", 10, 100.0);
    chunk1.adjustSymbolEndsToBoundingBox(null);
    chunk1.setFontName(fontName);
    chunk1.setFontWeight(400);

    // Chunk "Of" starting at x=70.8, gap=0.8 -> within neighbor threshold (0.1*10=1)
    // The gap is small enough that areNeighborsTextChunks returns true,
    // but large enough to represent a word boundary
    TextChunk chunk2 = new TextChunk(new BoundingBox(0, 70.8, 100.0, 85.8, 110.0),
        "Of", 10, 100.0);
    chunk2.adjustSymbolEndsToBoundingBox(null);
    chunk2.setFontName(fontName);
    chunk2.setFontWeight(400);

    contents.add(chunk1);
    contents.add(chunk2);

    TextProcessor.mergeCloseTextChunks(contents);
    contents = DocumentProcessor.removeNullObjectsFromList(contents);

    // Chunks with a small gap should be merged but with a space between words
    Assertions.assertEquals(1, contents.size(),
        "Text chunks with small gap should still be merged");
    // The words should have a space between them, not be concatenated
    Assertions.assertEquals("Evolution Of", ((TextChunk) contents.get(0)).getValue(),
        "Words separated by a gap should have a space between them");
}

@Test
public void testMeasureReplacementCharRatioAllReplacement() {
    List<IObject> contents = new ArrayList<>();
    contents.add(new TextChunk(new BoundingBox(1, 10.0, 10.0, 100.0, 20.0),
        "\uFFFD\uFFFD\uFFFD", 10, 10.0));

    double ratio = TextProcessor.measureReplacementCharRatio(contents);
    Assertions.assertEquals(1.0, ratio, 0.001);
}

