/**
     * Regression test for issue with words concatenation: text chunks with a small
     * gap between them should NOT be merged by mergeCloseTextChunks, because
     * unionTextChunks would concatenate values without a space. Instead, they must
     * remain separate so that TextLineProcessor.getTextLineWithSpaces can insert
     * proper spaces between them later in the pipeline.
     */
    @Test
    public void testMergeCloseTextChunksWithGapKeptSeparate() {
        List<IObject> contents = new ArrayList<>();
        String fontName = "Arial";

        // Chunk "Evolution" ending at x=70
        TextChunk chunk1 = new TextChunk(new BoundingBox(0, 10.0, 100.0, 70.0, 110.0),
            "Evolution", 10, 100.0);
        chunk1.adjustSymbolEndsToBoundingBox(null);
        chunk1.setFontName(fontName);
        chunk1.setFontWeight(400);

        // Chunk "Of" starting at x=70.8, gap=0.8 -> within neighbor threshold (0.1*10=1)
        // The gap is small enough that areNeighborsTextChunks returns true,
        // but large enough to represent a word boundary
        TextChunk chunk2 = new TextChunk(new BoundingBox(0, 70.8, 100.0, 85.8, 110.0),
            "Of", 10, 100.0);
        chunk2.adjustSymbolEndsToBoundingBox(null);
        chunk2.setFontName(fontName);
        chunk2.setFontWeight(400);

        contents.add(chunk1);
        contents.add(chunk2);

        TextProcessor.mergeCloseTextChunks(contents);
        contents = DocumentProcessor.removeNullObjectsFromList(contents);

        // Chunks with a gap should NOT be merged because unionTextChunks
        // would lose the necessary space between them. They remain separate
        // and TextLineProcessor will handle the spacing.
        Assertions.assertEquals(2, contents.size(),
            "Text chunks with a gap between them should stay separate");
        Assertions.assertEquals("Evolution", ((TextChunk) contents.get(0)).getValue());
        Assertions.assertEquals("Of", ((TextChunk) contents.get(1)).getValue());
    }

